import"./style-B4IgR0yf.js";const o=document.getElementById("setPathButton"),n=document.getElementById("setInventoryButton"),c=document.getElementById("viewActionsButton"),l=document.getElementById("logOutButton");o.addEventListener("click",()=>{window.location.replace("./setPath.html"),console.log("Set Path button clicked")});n.addEventListener("click",()=>{window.location.replace("./setInventory.html"),console.log("Set Inventory button clicked")});c.addEventListener("click",()=>{window.location.replace("./viewActions.html"),console.log("View Actions button clicked")});l.addEventListener("click",async()=>{const t=localStorage.getItem("adminUsername");try{await fetch("/api/admin-logout",{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({username:t})})}catch(e){console.error("Logout error:",e)}localStorage.removeItem("adminUsername"),window.location.replace("./adminLogin.html"),console.log("Log Out button clicked")});
